// src/pages/HomePage.jsx
import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import "./HomePage.css";

export default function HomePage() {
  const [showScroll, setShowScroll] = useState(false);

  useEffect(() => {
    const toggleScroll = () => {
      setShowScroll(window.scrollY > 300);
    };
    window.addEventListener("scroll", toggleScroll);
    return () => window.removeEventListener("scroll", toggleScroll);
  }, []);

  const scrollToTop = () => {
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  return (
    <>
      <header className="home-header">
        <div className="container">
          <h1>🎓 Campus Connect</h1>
          <nav>
            <a href="#hero">Home</a>
            <a href="#features">Features</a>
            <a href="#about">About</a>
            <a href="#contact">Contact</a>
            <Link to="/login" className="btn">Login</Link>
            <Link to="/register" className="btn">Register</Link>
          </nav>
        </div>
      </header>

      <section id="hero" className="hero-section">
        <h2>Welcome to Campus Connect</h2>
        <p>Your digital hub for notes, notices, events, and more.</p>
        <div className="hero-buttons">
          <Link to="/notes" className="btn-blue">View Notes</Link>
          <Link to="/events" className="btn-green">Explore Events</Link>
        </div>
      </section>

      <section id="features" className="features-section">
        <h2>📌 Features</h2>
        <div className="features-grid">
          <div className="feature-card">📚 Access Study Notes</div>
          <div className="feature-card">📢 View Latest Notices</div>
          <div className="feature-card">🎉 Join Campus Events</div>
          <div className="feature-card">👤 Manage Your Profile</div>
        </div>
      </section>

      <section id="about" className="about-section">
        <h2>📖 About Us</h2>
        <p>
          Campus Connect bridges students, HRs, and admins. From study materials
          to placement postings, we offer a centralized platform for all college activities.
        </p>
      </section>

      <section id="contact" className="contact-section">
        <h2>📞 Contact</h2>
        <p>Email: contact@campusconnect.com</p>
        <p>Phone: +91 9876543210</p>
      </section>

      <footer className="home-footer">© 2025 Campus Connect. All rights reserved.</footer>

      {showScroll && (
        <button className="scroll-top-btn" onClick={scrollToTop}>
          ↑
        </button>
      )}
    </>
  );
}
